mapper.select:
select * from lab_device d left join lab_sub l on d.lab_id = l.id
where d.is_deleted = 0 and l.is_deleted = 0

    and d.device_name like concat('%', #{deviceName}, '%')


    and d.device_price >= #{minPrice}


    and d.device_price <= #{maxPrice}


    and d.device_status = #{deviceStatus}

order by d.update_time desc
